import React from "react";
import { useNavigate } from "react-router-dom";

function Home() {

  const navigate = useNavigate();

  const features = [
    { title: "Live Tracking", icon: "📍", path: "/journey" },
    { title: "Emergency", icon: "🚨", path: "/sos" },
    { title: "Police Help", icon: "🚓", path: "/police" },
    { title: "Share", icon: "📲", path: "/share" },
  ];

  return (
    <>
      <style>{`

      .home {
        min-height: 100vh;
        padding: 20px;
        position: relative;
        overflow: hidden;
      }

      /* BACKGROUND GLOW */
      .bg-circle {
        position: absolute;
        border-radius: 50%;
        filter: blur(100px);
        z-index: 0;
      }

      .one {
        width: 250px;
        height: 250px;
        background: rgba(255, 79, 129, 0.5);
        top: -80px;
        left: -80px;
      }

      .two {
        width: 300px;
        height: 300px;
        background: rgba(255, 150, 180, 0.4);
        bottom: -100px;
        right: -100px;
      }

      /* HERO */
      .hero-card {
        position: relative;
        z-index: 1;

        background: linear-gradient(135deg, #ff7aa2, #ff4f81);
        color: white;

        padding: 25px;
        border-radius: 20px;

        text-align: center;

        box-shadow:
          0 10px 30px rgba(0,0,0,0.3),
          0 0 20px rgba(255,79,129,0.5);

        margin-bottom: 25px;

        animation: fadeUp 0.8s ease;
      }

      .hero-card button {
        background: white;
        color: #ff4f81;
        border: none;
        padding: 10px 20px;
        border-radius: 25px;
        cursor: pointer;
        transition: 0.3s;
      }

      .hero-card button:hover {
        transform: scale(1.08);
      }

      /* GRID */
      .quick-grid {
        display: grid;
        grid-template-columns: repeat(2, 1fr);
        gap: 15px;
        z-index: 1;
        position: relative;
      }

      /* CARD */
      .quick-card {
        background: rgba(255,255,255,0.85);
        backdrop-filter: blur(10px);

        padding: 20px;
        border-radius: 18px;

        text-align: center;
        cursor: pointer;

        box-shadow: 0 10px 25px rgba(0,0,0,0.25);

        transition: all 0.3s ease;
      }

      .quick-card:hover {
        transform: translateY(-10px) scale(1.05);

        box-shadow:
          0 15px 35px rgba(0,0,0,0.3),
          0 0 15px rgba(255,79,129,0.4);
      }

      .icon {
        font-size: 30px;
        margin-bottom: 8px;
      }

      /* FEATURE BANNER */
      .feature-banner {
        margin-top: 25px;

        background: rgba(255,255,255,0.2);
        backdrop-filter: blur(10px);

        padding: 20px;
        border-radius: 18px;

        color: white;
        text-align: center;

        box-shadow: 0 10px 30px rgba(0,0,0,0.3);
      }

      /* SOS */
      .floating-sos {
        position: fixed;
        bottom: 20px;
        right: 20px;

        width: 65px;
        height: 65px;

        border-radius: 50%;
        border: none;

        font-size: 24px;
        color: white;

        background: red;

        box-shadow:
          0 0 20px rgba(255,0,0,0.8),
          0 0 40px rgba(255,0,0,0.5);

        cursor: pointer;

        transition: 0.3s;
      }

      .floating-sos:hover {
        transform: scale(1.1);
      }

      /* ANIMATION */
      @keyframes fadeUp {
        from {
          opacity: 0;
          transform: translateY(30px);
        }
        to {
          opacity: 1;
          transform: translateY(0);
        }
      }

      `}</style>

      <div className="home">

        <div className="bg-circle one"></div>
        <div className="bg-circle two"></div>

        {/* HERO */}
        <div className="hero-card">
          <h1>💖 Stay Safe</h1>
          <p>Smart protection with real-time tracking & alerts</p>
          <button onClick={() => navigate("/journey")}>
            🚀 Start Journey
          </button>
        </div>

        {/* QUICK GRID */}
        <div className="quick-grid">
          {features.map((f, i) => (
            <div
              key={i}
              className="quick-card"
              onClick={() => navigate(f.path)}
            >
              <div className="icon">{f.icon}</div>
              <h3>{f.title}</h3>
            </div>
          ))}
        </div>

        {/* FEATURE */}
        <div className="feature-banner">
          <h3>🛰 AI Safety Monitoring</h3>
          <p>Detect unusual stops & trigger alerts automatically</p>
        </div>

        {/* SOS */}
        <button
          className="floating-sos"
          onClick={() => navigate("/sos")}
        >
          🚨
        </button>

      </div>
    </>
  );
}

export default Home;
